<div class="flex items-center gap-3 mb-8 bg-slate-100 dark:bg-slate-800 p-2 rounded-lg max-w-fit" aria-label="أدوات تحكم حجم الخط" aria-live="polite">
    <span class="text-xs text-slate-500 font-bold px-2">حجم الخط:</span>
    <button type="button" id="font-decrease" aria-label="تصغير حجم الخط" class="w-11 h-11 flex items-center justify-center rounded bg-slate-50 dark:bg-slate-700 text-slate-700 dark:text-slate-300 hover:text-primary font-bold transition-colors focus-visible:outline focus-visible:outline-2 focus-visible:outline-primary focus-visible:outline-offset-2" aria-pressed="false">-A</button>
    <button type="button" id="font-increase" aria-label="تكبير حجم الخط" class="w-11 h-11 flex items-center justify-center rounded bg-slate-50 dark:bg-slate-700 text-slate-700 dark:text-slate-300 hover:text-primary font-bold transition-colors focus-visible:outline focus-visible:outline-2 focus-visible:outline-primary focus-visible:outline-offset-2" aria-pressed="false">+A</button>
</div>
